import type { CompilationFixExecutionMode } from "../config.js";

export type FinalStatus = "全部修复" | "部分修复" | "未修复" | "执行异常";

export enum FixTaskType {
  FILE_GROUP = "file_group",
  CODE_GROUP = "code_group",
}

export interface CompilationError {
  error_code: string;
  file: string;
  line: number;
  column: number;
  message_details: string;
  suggestion?: string;
  code_context?: string;
  raw?: string;
}

export interface ErrorCodeCategory {
  error_code: string;
  error_message?: string;
  errors: CompilationError[];
  count: number;
  priority: number;
  fixed_count: number;
  remaining_count: number;
}

export interface ErrorFileCategory {
  error_file_path: string;
  errors: CompilationError[];
  count: number;
  priority: number;
  fixed_count: number;
  remaining_count: number;
}

export interface CompilationFixResult {
  code_category_errors: ErrorCodeCategory[];
  file_category_errors: ErrorFileCategory[];
  initial_count: number;
  fixed_count: number;
  remaining_count: number;
  modifications: string[];
  final_status: FinalStatus;
  all_remaining_errors: string;
}

export type BatchTaskStatus = "success" | "failed" | "no_fix" | "skipped";

export interface BatchTaskSummary {
  task_id: string;
  task_type: FixTaskType;
  status: BatchTaskStatus;
  initial_count: number;
  fixed_count: number;
  remaining_count: number;
  message: string;
}

export interface BatchSummary {
  round_num: number;
  batch_index: number;
  total_batches: number;
  tasks: BatchTaskSummary[];
}

export interface CompilationFixResponse {
  success: boolean;
  final_status: FinalStatus;
  progress: string;
  fixed_count: number;
  remaining_count: number;
  remaining_errors: string;
  code_category_errors: ErrorCodeCategory[];
  file_category_errors: ErrorFileCategory[];
  modifications: string[];
  metrics: {
    duration_ms: number;
    rounds: number;
    mode: CompilationFixExecutionMode;
  };
  batch_summaries?: BatchSummary[];
}

export interface FixTask {
  task_id: string;
  category_id: string;
  task_type: FixTaskType;
  payload: ErrorFileCategory[] | ErrorCodeCategory[];
  affected_files: Set<string> | null;
  priority: number;
}

export interface TaskReport {
  task_id: string;
  task_type: FixTaskType;
  success: boolean;
  fixed_count: number;
  error_message?: string;
}

export interface CompilationFixInput {
  project_abs_path: string;
}
